  // Find the ETH/USD perpetual market (WETH = perp, ETH = spot-only)
  const ethMarket = Object.values(marketsInfoData).find(
    (m) => tokensData[m.indexTokenAddress]?.symbol === "WETH" && !m.isSpotOnly
  );

  if (!ethMarket) throw new Error("ETH/USD market not found");

  const marketAddress = ethMarket.marketTokenAddress;
  const longTokenAddress = ethMarket.longTokenAddress;   // WETH (collateral for longs)

  const usdcAddress = Object.values(tokensData).find(
    (t) => t.symbol === "USDC"
  )?.address;

  if (!usdcAddress) throw new Error("USDC not found");

  console.log("Market:", marketAddress);
  console.log("Paying with: USDC", usdcAddress);
  console.log("Collateral:  WETH", longTokenAddress);

  // ─── Define order parameters ─────────────────────────────────────────────
  const PAY_AMOUNT_USDC = 100_000000n;   // 100 USDC (6 decimals) — adjust as needed

  // Limit price: $2800, scaled to 30 decimals
  // $2800 = 2800 * 10^30
  const LIMIT_PRICE = 2800n * 10n ** 30n;

  // ─── Place limit long order ───────────────────────────────────────────────
  console.log("\nPlacing limit long order...");
  console.log("  Trigger price: $2,800");
  console.log("  Pay amount:    100 USDC");
  console.log("  Leverage:      1x (no leverage)");

  const tx = await sdk.orders.long({
    marketAddress,
    payTokenAddress: usdcAddress,
    collateralTokenAddress: longTokenAddress,
    payAmount: PAY_AMOUNT_USDC,
    leverage: 10000n,          // 1x (basis points: 10000 = 1x)
    limitPrice: LIMIT_PRICE,   // Triggers when ETH oracle price <= $2,800
    allowedSlippageBps: 100,   // 1% slippage tolerance
    skipSimulation: true,
  });

  console.log("\n✅ Limit order submitted!");
  console.log("   Tx hash:", tx);
  console.log("\nOrder will execute when ETH price drops to or below $2,800.");
  console.log("The keeper will fill it at the oracle price at that moment.");
}

placeLimitLong().catch(console.error);
```

