const { getIncreasePositionAmounts, getDecreasePositionAmounts } = require("@gmx-io/sdk/utils/trade");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function openEthLongWithSlTp() {
  // ─── Setup ───────────────────────────────────────────────────────────────
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ─── Resolve addresses ───────────────────────────────────────────────────
  const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

  const ethMarket = Object.values(marketsInfoData).find(
    (m) => tokensData[m.indexTokenAddress]?.symbol === "WETH" && !m.isSpotOnly
  );
  if (!ethMarket) throw new Error("ETH/USD market not found");

  const marketAddress = ethMarket.marketTokenAddress;
  const usdcAddress = Object.values(tokensData).find((t) => t.symbol === "USDC")?.address;
  if (!usdcAddress) throw new Error("USDC not found");

  const marketInfo = marketsInfoData[marketAddress];
  const collateralToken = tokensData[usdcAddress];
  const indexToken = tokensData[ethMarket.indexTokenAddress];

  // Current ETH price (30-decimal scaled)
  const ethPriceRaw = indexToken.prices.minPrice;
  const ethPrice = Number(ethPriceRaw) / 1e30;
  console.log(`ETH price:  $${ethPrice.toFixed(2)}`);

  // ─── Define SL/TP prices ─────────────────────────────────────────────────
  // Adjust these to your desired levels
  const stopLossPrice  = BigInt(Math.round(ethPrice * 0.90 * 1e30)); // −10% from entry
  const takeProfitPrice = BigInt(Math.round(ethPrice * 1.15 * 1e30)); // +15% from entry

  console.log(`Stop-loss:   $${(Number(stopLossPrice)  / 1e30).toFixed(2)}  (−10%)`);
  console.log(`Take-profit: $${(Number(takeProfitPrice) / 1e30).toFixed(2)}  (+15%)`);

  // ─── Compute increase amounts ─────────────────────────────────────────────
  const { minCollateralUsd, minPositionSizeUsd } = await sdk.positions.getPositionsConstants();
  const uiFeeFactor = await sdk.utils.getUiFeeFactor();
  const userReferralInfo = undefined;

  const increaseAmounts = getIncreasePositionAmounts({
    marketInfo,
    indexToken,
    collateralToken,
    isLong: true,
    initialCollateralAmount: 200_000000n,   // $200 USDC
    initialCollateralToken: collateralToken,
    leverage: 50000n,                        // 5x
    triggerPrice: undefined,                 // market order
    position: undefined,                     // new position
    limitOrderType: undefined,
    userReferralInfo,
    uiFeeFactor,
    strategy: "leverageByCollateral",
  });

  // ─── Compute SL decrease amounts ─────────────────────────────────────────
  const stopLossAmounts = getDecreasePositionAmounts({
    marketInfo,
    collateralToken,
    isLong: true,
    position: undefined,                     // not yet open — uses increaseAmounts
    closeSizeUsd: increaseAmounts.sizeDeltaUsd, // full close
    keepLeverage: false,
    triggerPrice: stopLossPrice,
    triggerPriceType: "stopLoss",
    userReferralInfo,
    minCollateralUsd,
    minPositionSizeUsd,
    uiFeeFactor,
    isSetAcceptablePriceImpactEnabled: false,
  });

  // ─── Compute TP decrease amounts ─────────────────────────────────────────
  const takeProfitAmounts = getDecreasePositionAmounts({
    marketInfo,
    collateralToken,
    isLong: true,
    position: undefined,
    closeSizeUsd: increaseAmounts.sizeDeltaUsd, // full close
    keepLeverage: false,
    triggerPrice: takeProfitPrice,
    triggerPriceType: "takeProfit",
    userReferralInfo,
    minCollateralUsd,
    minPositionSizeUsd,
    uiFeeFactor,
    isSetAcceptablePriceImpactEnabled: false,
  });

  // ─── Submit: open + SL + TP in one transaction ───────────────────────────
  const tx = await sdk.orders.createIncreaseOrder({
    marketInfo,
    marketsInfoData,
    tokensData,
    collateralToken,
    isLong: true,
    allowedSlippage: 100,                    // 1%
    increaseAmounts,
    initialCollateralAmount: 200_000000n,
    initialCollateralToken: collateralToken,
    skipSimulation: true,

    // Sidecar SL/TP orders — attached and auto-cancelled when position closes
    createSltpEntries: [
      {
        id: "sl-1",
        decreaseAmounts: stopLossAmounts,
        txnType: "create",
      },
      {
        id: "tp-1",
        decreaseAmounts: takeProfitAmounts,
        txnType: "create",
      },
    ],
    cancelSltpEntries: [],
    updateSltpEntries: [],
  });

  console.log("\n✅ Position + SL/TP submitted:", tx);
  console.log("Keeper will execute the open order in 1–30 seconds.");
  console.log("SL and TP orders will activate once the position is live.");
}

openEthLongWithSlTp().catch(console.error);
```

---

**What gets created (3 orders in 1 tx):**

| Order | Type | Trigger | Action |
|-------|------|---------|--------|
| Open long | `MarketIncrease` | Immediately | Opens $1,000 notional position |
| Stop-loss | `StopLossDecrease` | ETH drops −10% | Full close, limits loss to ~$200 |
| Take-profit | `LimitDecrease` | ETH rises +15% | Full close, locks in ~$300 profit |

**Trigger logic:**
- Stop-loss fires when oracle price **≤** your SL price
- Take-profit fires when oracle price **≥** your TP price
- Both are **auto-cancelled** if you manually close the position

---

**Customize the levels** by changing these two lines:

