async function placeBtcLimitLong() {
  // ── Setup ──────────────────────────────────────────────────────────────────
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl:
      "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ── 1. Fetch markets and tokens ────────────────────────────────────────────
  console.log("Fetching market data...");
  const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

  // ── 2. Find BTC/USD perpetual market ──────────────────────────────────────
  // Look for WBTC or BTC as the index token symbol, excluding spot-only markets
  const btcMarket = Object.values(marketsInfoData).find((m) => {
    const indexToken = tokensData[m.indexTokenAddress];
    return (
      (indexToken?.symbol === "WBTC" || indexToken?.symbol === "BTC") &&
      !m.isSpotOnly
    );
  });

  if (!btcMarket) {
    throw new Error("BTC/USD perpetual market not found");
  }

  const indexToken = tokensData[btcMarket.indexTokenAddress];
  console.log(`Found market: ${indexToken.symbol}/USD`);
  console.log(`  Market address : ${btcMarket.marketTokenAddress}`);
  console.log(`  Long token     : ${tokensData[btcMarket.longTokenAddress]?.symbol}`);
  console.log(`  Short token    : ${tokensData[btcMarket.shortTokenAddress]?.symbol}`);

  // Current oracle price for reference
  const currentPrice =
    (btcMarket.indexToken?.prices?.minPrice ?? 0n) /
    10n ** 22n; // rough USD display (30 - 8 decimals)
  console.log(`  Current BTC price (approx): $${currentPrice.toLocaleString()}`);

  // ── 3. Resolve token addresses ─────────────────────────────────────────────
  // For a long, collateral should be the long token (WBTC) or USDC.
  // Using USDC as pay token is most common for limit longs.
