  if (!usdcToken) throw new Error("USDC token not found");

  const marketAddress   = btcMarket.marketTokenAddress;
  const longToken       = btcMarket.longTokenAddress;   // WBTC collateral
  const payTokenAddress = usdcToken.address;            // pay with USDC

  // ── 4. Define order parameters ─────────────────────────────────────────────
  const PAY_AMOUNT_USDC = 1_000_000_000n; // $1,000 USDC (6 decimals → 1000 * 1e6)
  const LEVERAGE_BPS    = 10_000n;        // 1x leverage (10000 bp = 1x)
  //   Position size ≈ $1,000 × 1x = $1,000 notional

  // Limit price: $58,000 scaled to 30 decimals
  // $58,000 = 58000 * 10^30 / 10^0  →  58000n * 10n**30n
  const LIMIT_PRICE = 58_000n * 10n ** 30n;

  console.log("\nOrder parameters:");
  console.log(`  Type           : Long Limit (LimitIncrease)`);
  console.log(`  Pay amount     : $1,000 USDC`);
  console.log(`  Leverage       : 1x`);
  console.log(`  Limit price    : $58,000`);
  console.log(`  Collateral     : ${tokensData[longToken]?.symbol}`);
  console.log(`  Slippage       : 1% (100 bps)`);

  // ── 5. Submit the limit order ──────────────────────────────────────────────
  console.log("\nSubmitting limit order...");

  const tx = await sdk.orders.long({
    marketAddress,
