I'll help you swap 0.1 ETH to USDC on GMX. Let me set this up for you.

```typescript
const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function swapEthToUsdc() {
  // Setup account and wallet
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const walletClient = createWalletClient({
    account,
    chain: arbitrum,
    transport: http("https://arb1.arbitrum.io/rpc"),
  });

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient,
  });

  // Fetch current token data to resolve addresses
  const { tokensData } = await sdk.markets.getMarketsInfo();

  // Find WETH and USDC token addresses
  const wethToken = Object.values(tokensData).find((t) => t.symbol === "WETH");
  const usdcToken = Object.values(tokensData).find((t) => t.symbol === "USDC");

  if (!wethToken || !usdcToken) {
    throw new Error("Could not find WETH or USDC token");
  }

  console.log(`Swapping 0.1 ETH → USDC`);
  console.log(`WETH address: ${wethToken.address}`);
  console.log(`USDC address: ${usdcToken.address}`);

  // 0.1 ETH = 0.1 * 10^18 = 100000000000000000n
  const fromAmount = 100000000000000000n; // 0.1 WETH (18 decimals)

  const tx = await sdk.orders.swap({
    fromTokenAddress: wethToken.address,
    toTokenAddress: usdcToken.address,
    fromAmount,
    allowedSlippageBps: 100, // 1% slippage tolerance
  });

  console.log("Swap order submitted:", tx);
  console.log("The keeper will execute it within a few seconds.");
}

swapEthToUsdc().catch(console.error);
```

**What this does:**
- **From:** 0.1 WETH (`100000000000000000n` — 18 decimals)
- **To:** USDC (amount determined by oracle price at execution)
- **Slippage:** 1% tolerance — the swap cancels if you'd receive less than 99% of the expected USDC
- **Chain:** Arbitrum (lowest fees, most liquidity)
- **Execution:** A keeper picks up the order and executes it within ~1–5 seconds using fresh oracle prices

**Before running:**
1. Set `PRIVATE_KEY` in your environment
2. Ensure your wallet holds at least 0.1 WETH (not native ETH — GMX uses wrapped ETH) plus a small amount of ETH for the execution fee
3. Run `npm install @gmx-io/sdk viem` if you haven't already

> **WETH vs ETH:** GMX trades WETH on Arbitrum. If you hold native ETH, you'll need to wrap it first via the WETH contract (`deposit()`) or use the GMX UI which handles wrapping automatically.

