const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function swapUsdcToEth() {
  // ─── Setup ───────────────────────────────────────────────────────────────
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ─── Resolve Token Addresses ─────────────────────────────────────────────
  const { tokensData } = await sdk.markets.getMarketsInfo();

  const usdcToken = Object.values(tokensData).find((t) => t.symbol === "USDC");
  const wethToken = Object.values(tokensData).find((t) => t.symbol === "WETH");

  if (!usdcToken || !wethToken) {
    throw new Error("Could not find USDC or WETH token");
  }

  console.log("USDC address:", usdcToken.address);
  console.log("WETH address:", wethToken.address);

  // ─── Check Balance ───────────────────────────────────────────────────────
  const { balancesData } = await sdk.tokens.getTokensBalances();
  const usdcBalance = balancesData?.[usdcToken.address] ?? 0n;
  const usdcAmount = 100_000000n; // 100 USDC (6 decimals)

  console.log(`USDC balance: ${Number(usdcBalance) / 1e6} USDC`);

  if (usdcBalance < usdcAmount) {
    throw new Error(
      `Insufficient USDC balance. Have ${Number(usdcBalance) / 1e6}, need 100`
    );
  }

  // ─── Execute Swap ────────────────────────────────────────────────────────
  console.log("Swapping 100 USDC → ETH...");

  const result = await sdk.orders.swap({
    fromTokenAddress: usdcToken.address,
    toTokenAddress: wethToken.address,
    fromAmount: usdcAmount,       // Exact input: 100 USDC
    allowedSlippageBps: 100,      // 1% slippage tolerance
  });

  console.log("✅ Swap order submitted!");
  console.log("Transaction hash:", result);
  console.log("The keeper will execute the swap within 1–5 seconds.");

  return result;
}

swapUsdcToEth().catch(console.error);
```

