```typescript
const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, createPublicClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

// Initialize SDK for Arbitrum
const sdk = new GmxSdk({
  chainId: 42161,
  rpcUrl: "https://arb1.arbitrum.io/rpc",
  oracleUrl: "https://arbitrum-api.gmxinfra.io",
  subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
  account: process.env.BOT1_ADDRESS,
  walletClient: createWalletClient({
    account: privateKeyToAccount(process.env.BOT1_PRIVATE_KEY),
    chain: arbitrum,
    transport: http("https://arb1.arbitrum.io/rpc"),
  }),
});

// Fetch markets and tokens
const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

// Find ETH/USD perpetual market (WETH index, not spot-only)
const ethMarket = Object.values(marketsInfoData).find(
  (m) => tokensData[m.indexTokenAddress]?.symbol === "WETH" && !m.isSpotOnly
);

if (!ethMarket) throw new Error("ETH/USD market not found");

const marketAddress = ethMarket.marketTokenAddress;
const longTokenAddress = ethMarket.longTokenAddress;   // WETH
const shortTokenAddress = ethMarket.shortTokenAddress; // USDC

// Find USDC token address
const usdcToken = Object.values(tokensData).find((t) => t.symbol === "USDC");
if (!usdcToken) throw new Error("USDC token not found");

console.log("Market:", ethMarket.name ?? marketAddress);
console.log("ETH Price:", (tokensData[ethMarket.indexTokenAddress].prices.minPrice / BigInt(1e24)).toString(), "USD");
console.log("USDC Address:", usdcToken.address);

// Open 10x long ETH position
// $500 USDC collateral = 500 * 10^6 (USDC has 6 decimals)
const payAmount = 500_000_000n; // 500 USDC
const leverage = 100_000n;      // 10x in basis points (10 * 10,000)

const tx = await sdk.orders.long({
  marketAddress,
  payTokenAddress: usdcToken.address,
  collateralTokenAddress: longTokenAddress, // WETH collateral for longs
  payAmount,
  leverage,
  allowedSlippageBps: 100, // 1% slippage
  skipSimulation: true,
});

console.log("✅ Order submitted!");
console.log("Tx Hash:", tx.hash ?? tx);
console.log("Position size: ~$5,000 (10x on $500)");
console.log("Keeper will execute in 1–30 seconds.");
```

---

**What this does:**
| Parameter | Value |
|-----------|-------|
| Market | ETH/USD perpetual |
| Collateral | 500 USDC |
| Leverage | 10x (`100,000` bps) |
| Position Size | ~$5,000 notional |
| Collateral Token | WETH (standard for longs) |
| Slippage | 1% |

**Fees to expect:**
- **Opening fee:** ~0.04–0.06% of position size (~$2–3)
- **Execution fee:** Small ETH gas fee (refunded if overestimated)
- **Funding/borrowing:** Accrues over time while position is open

**Next steps after execution:**
- Monitor with `sdk.positions.getPositionsInfo()`
- Set a stop-loss with `createDecreaseOrder()` + `StopLossDecrease`
- Close with `getDecreasePositionAmounts()` + `createDecreaseOrder()`

> ⚠️ Make sure `BOT1_ADDRESS` and `BOT1_PRIVATE_KEY` are set in your environment, and that the wallet holds enough USDC + ETH for the execution fee.

