const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, createPublicClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function openBtcLong() {
  // ─── 1. Setup ─────────────────────────────────────────────────────────────
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const walletClient = createWalletClient({
    account,
    chain: arbitrum,
    transport: http("https://arb1.arbitrum.io/rpc"),
  });

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient,
  });

  // ─── 2. Fetch markets and tokens ──────────────────────────────────────────
  console.log("Fetching market data...");
  const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

  // ─── 3. Find BTC/USD market ───────────────────────────────────────────────
  // Look for a non-spot BTC perpetual market
  const btcMarket = Object.values(marketsInfoData).find((m) => {
    const indexToken = tokensData[m.indexTokenAddress];
    return (
      (indexToken?.symbol === "WBTC" || indexToken?.symbol === "BTC") &&
      !m.isSpotOnly
    );
  });

  if (!btcMarket) {
    throw new Error("BTC/USD perpetual market not found");
  }

  console.log(`Found market: ${btcMarket.name ?? btcMarket.marketTokenAddress}`);
  console.log(`  Index token:  ${tokensData[btcMarket.indexTokenAddress]?.symbol}`);
  console.log(`  Long token:   ${tokensData[btcMarket.longTokenAddress]?.symbol}`);
  console.log(`  Short token:  ${tokensData[btcMarket.shortTokenAddress]?.symbol}`);

  // ─── 4. Resolve token addresses ───────────────────────────────────────────
  const marketAddress = btcMarket.marketTokenAddress;
  const longTokenAddress = btcMarket.longTokenAddress;   // WBTC (collateral for longs)
  const shortTokenAddress = btcMarket.shortTokenAddress; // USDC

  // Use USDC as the pay token (most common)
  const usdcToken = Object.values(tokensData).find((t) => t.symbol === "USDC");
  if (!usdcToken) throw new Error("USDC not found");

  const usdcAddress = usdcToken.address;

  // ─── 5. Check current BTC price ───────────────────────────────────────────
  const btcToken = tokensData[btcMarket.indexTokenAddress];
  const btcPriceUsd =
    Number(btcToken.prices.minPrice + btcToken.prices.maxPrice) /
    2 /
    1e30;
  console.log(`\nCurrent BTC price: ~$${btcPriceUsd.toLocaleString()}`);

  // ─── 6. Define position size ──────────────────────────────────────────────
  // Collateral: 100 USDC → with 20x leverage → ~$2,000 position size
  const COLLATERAL_USDC = 100; // USD
  const payAmount = BigInt(COLLATERAL_USDC * 1_000_000); // USDC has 6 decimals

  console.log(`\nOpening position:`);
  console.log(`  Collateral:    $${COLLATERAL_USDC} USDC`);
  console.log(`  Leverage:      20x`);
  console.log(`  Position size: ~$${COLLATERAL_USDC * 20} USD`);
  console.log(`  Direction:     LONG`);

  // ─── 7. Open the long position ────────────────────────────────────────────
  // leverage is in basis points: 20x = 200,000 bps
  const tx = await sdk.orders.long({
    marketAddress,
    payTokenAddress: usdcAddress,
    collateralTokenAddress: longTokenAddress, // WBTC collateral for longs
    payAmount,
    leverage: 200_000n,        // 20x (basis points: 10,000 = 1x)
    allowedSlippageBps: 100,   // 1% slippage tolerance
    skipSimulation: true,
  });

  console.log("\n✅ Order submitted!");
  console.log(`   Tx hash: ${tx?.hash ?? JSON.stringify(tx)}`);
  console.log("   The keeper will execute this within ~5–30 seconds.");
}

openBtcLong().catch(console.error);
```

