    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ─── 2. Resolve token addresses ───────────────────────────────────────────

  const { tokensData } = await sdk.markets.getMarketsInfo();

  // Find USDC.e (bridged USDC on Arbitrum, distinct from native USDC)
  const usdce = Object.values(tokensData).find((t) => t.symbol === "USDC.e");
  const weth  = Object.values(tokensData).find((t) => t.symbol === "WETH");

  if (!usdce || !weth) {
    throw new Error(
      `Token not found — available: ${Object.values(tokensData).map((t) => t.symbol).join(", ")}`
    );
  }

  console.log("USDC.e address:", usdce.address);
  console.log("WETH  address:", weth.address);

  // ─── 3. Check balance ─────────────────────────────────────────────────────

  const { balancesData } = await sdk.tokens.getTokensBalances({
    account: account.address,
    tokensList: [{ address: usdce.address }],
  });

  const balance = balancesData?.[usdce.address] ?? 0n;
  const swapAmount = 1000n * 10n ** BigInt(usdce.decimals); // 1000 USDC.e (6 decimals → 1_000_000_000n)

  console.log(`USDC.e balance: ${balance / 10n ** BigInt(usdce.decimals)} USDC.e`);

  if (balance < swapAmount) {
    throw new Error(
      `Insufficient balance: have ${balance}, need ${swapAmount}`
    );
  }

  // ─── 4. Execute swap ──────────────────────────────────────────────────────

  console.log(`\nSwapping 1000 USDC.e → ETH with 1% slippage tolerance...`);

  const tx = await sdk.orders.swap({
    fromTokenAddress: usdce.address,
    toTokenAddress:   weth.address,   // GMX routes WETH; you receive native ETH
    fromAmount:       swapAmount,     // exact input: 1000 USDC.e
    allowedSlippageBps: 100,          // 1% slippage
    skipSimulation: true,
  });

  console.log("\n✅ Swap order submitted!");
  console.log("Tx hash:", tx?.hash ?? tx);
  console.log("The GMX keeper will execute within ~5 seconds.");
  console.log("You will receive ETH (unwrapped from WETH automatically).");
